  },
  {
    "name": "tax_authority_fa",
    "description": "Matches abbreviated tax authorities starting with 'FA' followed by location names.",
    "format": "regex",
    "content": "\\bFA\\s+[A-Z][a-zA-Z\\-\\s]+(?:\\s+[A-Z][a-zA-Z\\-\\s]+)*",
    "priority": 4,
    "output_template": {
      "text": "$0",
      "start": "$start",
      "end": "$end",
      "type": "organisation"
    },
    "output_key": "entities"
  },
  {
    "name": "company_other",
    "description": "Matches other organization names that do not end in GMBH but are capitalized and appear in legal contexts.",
    "format": "regex",
    "content": "\\b[A-Z][a-zA-Z\\-]+(?:\\s+[A-Z][a-zA-Z\\-]+)*\\b(?=,|\\s+von|\\s+des|\\s+der|\\s+bei|\\s+gegen)",
    "priority": 2,
    "output_template": {
      "text": "$0",
